const { S3Client, GetObjectCommand, PutObjectCommand } = require('@aws-sdk/client-s3');
const crypto = require('crypto');

const s3Client = new S3Client({ region: process.env.AWS_REGION });

const ALLOWED_BUCKET_PREFIX = process.env.ALLOWED_SOURCE_BUCKET_PREFIX || '';
const ALLOWED_FILE_EXTENSIONS = ['.txt', '.json', '.csv', '.xml', '.pdf'];
const MAX_FILE_SIZE = 10 * 1024 * 1024;
const OUTPUT_BUCKET = process.env.OUTPUT_BUCKET;
const ALLOWED_OUTPUT_BUCKET_PATTERN = /^[a-z0-9][a-z0-9\-]{1,61}[a-z0-9]$/;

function validateBucketName(bucketName) {
  if (!bucketName || typeof bucketName !== 'string') {
    throw new Error('Invalid bucket name');
  }
  
  if (ALLOWED_BUCKET_PREFIX && !bucketName.startsWith(ALLOWED_BUCKET_PREFIX)) {
    throw new Error('Bucket name not in allowed prefix');
  }
  
  if (!/^[a-z0-9][a-z0-9\-\.]{1,61}[a-z0-9]$/.test(bucketName)) {
    throw new Error('Bucket name contains invalid characters');
  }
  
  return true;
}

function validateObjectKey(key) {
  if (!key || typeof key !== 'string') {
    throw new Error('Invalid object key');
  }
  
  if (key.length > 1024) {
    throw new Error('Object key too long');
  }
  
  if (key.includes('..') || key.startsWith('/')) {
    throw new Error('Path traversal detected in object key');
  }
  
  const decodedKey = decodeURIComponent(key);
  if (decodedKey.includes('..') || decodedKey.startsWith('/')) {
    throw new Error('Path traversal detected in decoded object key');
  }
  
  const extension = decodedKey.substring(decodedKey.lastIndexOf('.')).toLowerCase();
  if (!ALLOWED_FILE_EXTENSIONS.includes(extension)) {
    throw new Error(`File extension ${extension} not allowed`);
  }
  
  return decodedKey;
}

function sanitizeFilename(filename) {
  const basename = filename.substring(filename.lastIndexOf('/') + 1);
  const sanitized = basename.replace(/[^a-zA-Z0-9\-_.]/g, '_');
  
  if (sanitized.length === 0 || sanitized.length > 255) {
    throw new Error('Invalid filename after sanitization');
  }
  
  return sanitized;
}

function validateOutputBucket(bucketName) {
  if (!bucketName || typeof bucketName !== 'string') {
    throw new Error('Output bucket not configured');
  }
  
  if (!ALLOWED_OUTPUT_BUCKET_PATTERN.test(bucketName)) {
    throw new Error('Invalid output bucket name');
  }
  
  return true;
}

async function streamToBuffer(stream, maxSize) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    let totalSize = 0;
    
    stream.on('data', (chunk) => {
      totalSize += chunk.length;
      if (totalSize > maxSize) {
        stream.destroy();
        reject(new Error('File size exceeds maximum allowed'));
        return;
      }
      chunks.push(chunk);
    });
    
    stream.on('error', reject);
    stream.on('end', () => resolve(Buffer.concat(chunks)));
  });
}

function processFileContent(buffer, contentType) {
  const hash = crypto.createHash('sha256').update(buffer).digest('hex');
  
  const processedData = {
    timestamp: new Date().toISOString(),
    fileSize: buffer.length,
    contentHash: hash,
    contentType: contentType || 'application/octet-stream',
    processed: true
  };
  
  return Buffer.from(JSON.stringify(processedData, null, 2));
}

exports.handler = async (event) => {
  const results = [];
  
  try {
    if (!OUTPUT_BUCKET) {
      throw new Error('OUTPUT_BUCKET environment variable not set');
    }
    
    validateOutputBucket(OUTPUT_BUCKET);
    
    for (const record of event.Records) {
      try {
        if (record.eventSource !== 'aws:s3') {
          console.warn('Skipping non-S3 event');
          continue;
        }
        
        if (!record.eventName.startsWith('ObjectCreated:')) {
          console.warn('Skipping non-PUT event');
          continue;
        }
        
        const bucketName = record.s3.bucket.name;
        const objectKey = record.s3.object.key;
        
        validateBucketName(bucketName);
        const validatedKey = validateObjectKey(objectKey);
        
        console.log(`Processing file from bucket: ${bucketName.substring(0, 20)}...`);
        
        const getCommand = new GetObjectCommand({
          Bucket: bucketName,
          Key: validatedKey
        });
        
        const response = await s3Client.send(getCommand);
        const fileBuffer = await streamToBuffer(response.Body, MAX_FILE_SIZE);
        
        const processedContent = processFileContent(fileBuffer, response.ContentType);
        
        const originalFilename = validatedKey.substring(validatedKey.lastIndexOf('/') + 1);
        const sanitizedFilename = sanitizeFilename(originalFilename);
        const outputKey = `processed/${sanitizedFilename}.json`;
        
        const putCommand = new PutObjectCommand({
          Bucket: OUTPUT_BUCKET,
          Key: outputKey,
          Body: processedContent,
          ContentType: 'application/json',
          ServerSideEncryption: 'AES256',
          Metadata: {
            'original-size': fileBuffer.length.toString(),
            'processed-date': new Date().toISOString()
          }
        });
        
        await s3Client.send(putCommand);
        
        results.push({
          status: 'success',
          outputKey: outputKey
        });
        
      } catch (recordError) {
        console.error('Error processing record:', recordError.message);
        results.push({
          status: 'error',
          error: recordError.message
        });
      }
    }
    
    return {
      statusCode: 200,
      body: JSON.stringify({
        message: 'Processing complete',
        results: results
      })
    };
    
  } catch (error) {
    console.error('Fatal error:', error.message);
    throw error;
  }
};